import{_ as a,o as t,c as n,a2 as r}from"./chunks/framework.7R1OEGYz.js";const u=JSON.parse('{"title":"Send and the guard","description":"","frontmatter":{},"headers":[],"relativePath":"using/send.md","filePath":"using/send.md"}'),o={name:"using/send.md"};function i(d,e,s,h,l,c){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="send-and-the-guard" tabindex="-1">Send and the guard <a class="header-anchor" href="#send-and-the-guard" aria-label="Permalink to &quot;Send and the guard&quot;">​</a></h1><p>Sending is where Suho earns its name. The wallet resolves who you are paying and warns you before you pay a stranger.</p><h2 id="sending-to-a-name" tabindex="-1">Sending to a name <a class="header-anchor" href="#sending-to-a-name" aria-label="Permalink to &quot;Sending to a name&quot;">​</a></h2><p>Type a up.id name or a 0x address in the recipient field. The app resolves it live, with a short debounce.</p><ul><li><strong>Verified human.</strong> The recipient card shows a red seal and &quot;Verified human&quot;. Enter an amount and send.</li><li><strong>Unverified address.</strong> The card shows an amber warning: &quot;Unverified address. Suho can&#39;t identify who this is.&quot;</li></ul><p>Enter the amount and tap Send. Complete the passkey prompt. A toast tracks the transaction: pending, then &quot;Sent&quot; with the real measured confirmation time, then &quot;Confirmed&quot; with an explorer link.</p><p>A verified send is proven live. <a href="https://sepolia-explorer.giwa.io/tx/0x5140fa4f8d3081b8f1accd82b1df4c157410cd055c888aead21463ff1263c8ec" target="_blank" rel="noreferrer">View the transaction.</a></p><h2 id="the-guard" tabindex="-1">The guard <a class="header-anchor" href="#the-guard" aria-label="Permalink to &quot;The guard&quot;">​</a></h2><p>Every transfer passes through <code>OndolTransferGuard</code> before it runs. The guard decides one of three outcomes.</p><ul><li><strong>Verified recipient.</strong> Allowed silently.</li><li><strong>Unverified recipient, small amount.</strong> Allowed with a warning event. The app shows the amber card. The chain does not block small sends.</li><li><strong>Unverified recipient, large amount.</strong> Held for a one-time code. The threshold is 0.01 ether.</li></ul><p>A small warned send is proven live. <a href="https://sepolia-explorer.giwa.io/tx/0xf1ab1cdc2243ea49fc054a4b6fd4e54edb6bde80be7d04be6494d8fc37bf300d" target="_blank" rel="noreferrer">View the transaction.</a></p><h2 id="the-one-time-code" tabindex="-1">The one-time code <a class="header-anchor" href="#the-one-time-code" aria-label="Permalink to &quot;The one-time code&quot;">​</a></h2><p>For a large transfer to a stranger, an interstitial appears with six code boxes and a countdown. The code is on the <a href="/docs/internals/codes">verification service</a>. It is single-use and bound to this exact recipient and amount.</p><p>A drainer that observes the code cannot reuse it. The binding is <code>suho.guard:&lt;account&gt;:&lt;recipient&gt;:&lt;amount&gt;</code>. Enter the code and send.</p><p>If the code expires while the interstitial is open, the submit button becomes &quot;Request a new code&quot;.</p><p>An OTP-gated send is proven live. <a href="https://sepolia-explorer.giwa.io/tx/0x3c3fb31d608d984388cdadc37e81dcf9f631412542a1d83f6b3e67782ca24b03" target="_blank" rel="noreferrer">View the transaction.</a></p>',16)])])}const f=a(o,[["render",i]]);export{u as __pageData,f as default};
